public Number read(JsonReader in) throws IOException { 
  JsonToken jsonToken = in.peek(); if (jsonToken == JsonToken.NULL) {
    in.nextNull(); return null;

  } else if (jsonToken == JsonToken.NUMBER) {
    return new LazilyParsedNumber(in.nextString());

  } else if (jsonToken == JsonToken.STRING) {
    return new LazilyParsedNumber(in.nextString());

  } else {
    throw new JsonSyntaxException("Expecting number, got: " + jsonToken);
  }
}

public Number read(JsonReader in) throws IOException {
  JsonToken jsonToken = in.peek();
  switch (jsonToken) {
    case NULL:
      in.nextNull();
      return null;
    case NUMBER:
      return new LazilyParsedNumber(in.nextString());
    case STRING:
      return new LazilyParsedNumber(in.nextString());
    default:
      throw new JsonSyntaxException("Expecting number or string, got: " + jsonToken);
  }
}

